class Solution:
    def getDecimalValue(self, head) -> int:
        bits = []
        node = head
        while node:
            bits.append(node.val)
            node = node.next
        return int(''.join(str(b) for b in bits), 2)

solutions.python:
class Solution:
    def getDecimalValue(self, head) -> int:
        result = 0
        while head:
            result = (result << 1) | head.val
            head = head.next
        return result

